import{_ as p,c as e,o as l,ag as t}from"./chunks/framework.ELrfyV9R.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{"type":"inbox","status":"pending","source":"web-clipper","url":"https://x.com/LawrenceW_Zen/status/2039194696740937974","created":"2026-04-10T00:00:00.000Z"},"headers":[],"relativePath":"ai/bookmark/从 0 开始安全稳定用上官方 Claude Code：完整指南.md","filePath":"ai/bookmark/从 0 开始安全稳定用上官方 Claude Code：完整指南.md","lastUpdated":1776858534000}'),o={name:"ai/bookmark/从 0 开始安全稳定用上官方 Claude Code：完整指南.md"};function r(i,a,s,n,m,d){return l(),e("div",null,a[0]||(a[0]=[t('<p><img src="https://pbs.twimg.com/media/HEyhZyXakAA_Ac1?format=jpg&amp;name=large" alt="图像"></p><p><strong>本文目标：一篇文章，带你从零开始，安全、稳定、完整地用上官方 Claude Code。</strong></p><p><strong>本教程适用系统：Mac、Linux、Windows。</strong></p><p>之前我分三篇写了这个系列，很多朋友反馈说希望有一个完整版，从头到尾一次看完。这篇就是整合版，把完整路径串成一条线。</p><p>整条链路分四步：</p><ol><li><strong>先跑起来</strong> — 用最低成本把 Claude Code 装好、跑通</li><li><strong>搭纯净网络</strong> — VPS + 住宅 IP，解决网络环境问题</li><li><strong>穿上防弹衣</strong> — 用 AdsPower 指纹浏览器管理 Claude 账号</li><li><strong>正式订阅</strong> — Apple 礼品卡完成官方订阅</li></ol><p>废话不多说，直接开始。</p><h2 id="第一部分-先跑起来-—-用最低成本把-claude-code-装好、跑通" tabindex="-1">第一部分：先跑起来 — 用最低成本把 Claude Code 装好、跑通 <a class="header-anchor" href="#第一部分-先跑起来-—-用最低成本把-claude-code-装好、跑通" aria-label="Permalink to &quot;第一部分：先跑起来 — 用最低成本把 Claude Code 装好、跑通&quot;">​</a></h2><p><strong>敲重点：前排提醒！</strong></p><p>如果你已经有 Codex 正在使用，可以忽略下面的安装过程，直接让 Codex 协助你安装好 Claude Code，然后直接进入第二部分。</p><p>安装开始部分没有改动请看原来的文章</p><blockquote><p>3月2日</p></blockquote><h2 id="第二部分-搭建纯净网络环境-—-vps-住宅-ip" tabindex="-1">第二部分：搭建纯净网络环境 — VPS + 住宅 IP <a class="header-anchor" href="#第二部分-搭建纯净网络环境-—-vps-住宅-ip" aria-label="Permalink to &quot;第二部分：搭建纯净网络环境 — VPS + 住宅 IP&quot;">​</a></h2><blockquote><p>继续前排提醒！如果你已经有 Codex，可以直接将下面的提示词给 Codex，帮你完成 VPS + 住宅 IP 的配置。</p></blockquote><p>上一部分我们先把 Claude Code 跑通了，为什么没直接写官方订阅？</p><p>因为 Claude 官方订阅对网络环境要求更高：固定、稳定、可控，缺一条都容易翻车，被官方封号。</p><p>这一部分我们要用 AI 时代的办法：一句提示词，让 Claude Code 完成你的 VPS + 住宅 IP 配置。</p><blockquote><p>说到底出海最好的方案还是自己搭 VPS，但 99% 的人都被搭建难度劝退。现在有了 AI，自己搭 VPS 已经是不二之选。搞起来吧！</p></blockquote><p><strong>你买到VPS 跟 IP 资源后，通常会有这些信息：</strong></p><ul><li>VPS：IP、root 初始密码（或初始登录方式）</li><li>住宅出口：IP、用户名、密码</li></ul><h2 id="开始配置" tabindex="-1">开始配置 <a class="header-anchor" href="#开始配置" aria-label="Permalink to &quot;开始配置&quot;">​</a></h2><blockquote><p>之前文章的提示词我又优化了一版，会更好用，更安全。</p></blockquote><p><strong>直接复制评论区的提示词内容给 Claude Code，把里面的占位信息替换成你自己的，然后一直确认即可。</strong></p><p>搭建过程中，有一个关键节点需要暂停：必须手动测试无密码密钥登录是否成功。命令会由 Claude Code 输出到终端，你直接复制粘贴即可。</p><p>Claude Code 搭建完 VPS 的所有服务后，会直接调用本地代理软件。</p><p>执行结束之后，会打印一个汇总信息，大家根据需要复制保存一下，或者让 Claude Code 给你存好档。</p><p><img src="https://pbs.twimg.com/media/HEycb41awAAqLWm?format=jpg&amp;name=large" alt="图像"></p><h2 id="测试搭建结果" tabindex="-1">测试搭建结果 <a class="header-anchor" href="#测试搭建结果" aria-label="Permalink to &quot;测试搭建结果&quot;">​</a></h2><p>根据最终 Claude Code 输出的验证方法，复制命令到终端测试</p><blockquote><p>curl -x <a href="http://127.0.0.1:7897" target="_blank" rel="noreferrer">http://127.0.0.1:7897</a> <a href="https://ipinfo.io/" target="_blank" rel="noreferrer">https://ipinfo.io</a></p></blockquote><p><img src="https://pbs.twimg.com/media/HEyciDUbsAAIU2r?format=jpg&amp;name=large" alt="图像"></p><h2 id="第三部分-给你的账号穿上马甲-—-指纹浏览器" tabindex="-1">第三部分：给你的账号穿上马甲 — 指纹浏览器 <a class="header-anchor" href="#第三部分-给你的账号穿上马甲-—-指纹浏览器" aria-label="Permalink to &quot;第三部分：给你的账号穿上马甲 — 指纹浏览器&quot;">​</a></h2><p>网络环境搞定了，但还差一层保护：你的浏览器环境。</p><p>光有干净的 IP 还不够。Claude 不只看你的 IP，还会看你的浏览器环境。</p><p>很多人被封号、被跳验证，不是因为 IP 有问题，而是因为浏览器指纹暴露了你的真实环境——Canvas、WebGL、时区、语言这些特征，每次登录都不一样，反而更容易触发风控。</p><p>为了更安全，我用了指纹浏览器 AdsPower，给 Claude 账号创建一个固定的、干净的浏览器环境。</p><h2 id="什么是指纹浏览器" tabindex="-1">什么是指纹浏览器 <a class="header-anchor" href="#什么是指纹浏览器" aria-label="Permalink to &quot;什么是指纹浏览器&quot;">​</a></h2><p>一句话：让你拥有一个<strong>固定的、干净的、独立的浏览器环境</strong>。</p><p>你可以把它理解成：在你的电脑上开了个虚拟电脑，有自己的浏览器指纹、Cookie、代理配置，跟你的真实机器完全隔离。</p><p>它的信息<strong>固定不变</strong>。对网站来说，你就是一个每天都从同一台电脑、同一个地方登录的真实用户。这比每次指纹都变的情况更安全。</p><h2 id="实操-用-adspower-为-claude-账号创建专属环境" tabindex="-1">实操：用 AdsPower 为 Claude 账号创建专属环境 <a class="header-anchor" href="#实操-用-adspower-为-claude-账号创建专属环境" aria-label="Permalink to &quot;实操：用 AdsPower 为 Claude 账号创建专属环境&quot;">​</a></h2><p>AdsPower 是老牌的指纹浏览器软件，稳定好用，我最近开通了 Max Plan 就开始用这个登录了。另外，免费版个人使用完全够，一个人，同时拥有，也就一两个号。</p><p>后面如果你有多个账号需要管理，按同样的方式加就行。</p><p><strong>1. 下载安装 AdsPower</strong></p><p>前往 <a href="https://www.adspower.net/share/z03P9q" target="_blank" rel="noreferrer">下载安装 AdsPower</a> ：支持 Mac、Windows、Linux。</p><p>注册账号后，进入设置，找到 API Key 并复制保存。后面如果你想用 Claude Code 自动化配置（高级玩法），会用到这个 Key。</p><p><img src="https://pbs.twimg.com/media/HEyc_H4a8AAUuSQ?format=jpg&amp;name=large" alt="图像"></p><p><strong>2. 创建 Profile</strong></p><p>选择左边的「分组管理」，右上角的创建分组，然后输入分组名称，新建分组</p><p><img src="https://pbs.twimg.com/media/HEydDTBakAAKewe?format=jpg&amp;name=large" alt="图像"></p><p>左上角新建浏览器 Profile，输入名称，选择分组「Claude 账号」</p><p><img src="https://pbs.twimg.com/media/HEydGbObUAA0rPZ?format=jpg&amp;name=large" alt="图像"></p><p>代理信息选择直连。因为本地已经搭建好代理了，流量会通过本地代理客户端统一走代理（如果你开了 TUN 模式，选直连即可；如果没开 TUN，后面第 4 步会教你手动填代理端口）。</p><p><img src="https://pbs.twimg.com/media/HEydWdVakAAkXcl?format=jpg&amp;name=large" alt="图像"></p><p><strong>3. 配置浏览器指纹</strong></p><p>创建新建时，重点配置这几项：</p><ul><li><strong>UA 系统</strong>：选 Mac OS X（跟你的实际系统保持一致更自然）</li><li><strong>Canvas 指纹</strong>：开启噪声</li><li><strong>WebGL 指纹</strong>：开启噪声</li><li><strong>Audio 指纹</strong>：开启噪声</li><li><strong>WebRTC</strong>：禁用（防止泄露真实 IP）</li><li><strong>端口扫描保护</strong>：开启</li></ul><p>这些配置的目的是：Profile 有独立的、固定的指纹，但指纹本身看起来像一个真实用户。 如图，确保都是打开的。</p><p><img src="https://pbs.twimg.com/media/HEydQ-UaIAEQTvv?format=jpg&amp;name=large" alt="图像"></p><p><strong>4. 配置代理 — 这里有个建议</strong></p><p>如果你就一个住宅 IP 跟 VPS：统一走本地代理客户端（比如 Clash Verge Rev），在代理客户端的规则里做分流。我们都是个人用户，号也不多，这样最方便了</p><p>Profile 的代理填 127.0.0.1:7897（Clash 的本地端口），然后在 Clash 的规则里配好哪些域名走住宅、哪些走普通代理。前面第二部分的提示词已经帮你配好了这些分流规则。</p><p>这样做的好处：</p><ol><li><strong>集中管理</strong>：改代理规则只需要动 Clash，不用改 Profile</li><li><strong>敏感信息不散落</strong>：住宅 IP 的账号密码只存在代理客户端里，不用填到 AdsPower</li><li><strong>灵活切换</strong>：想换节点直接在 Clash 里切，Profile 自动生效</li></ol><blockquote><p>AdsPower 打开后的<strong>启动页会显示一个 IP 检测结果，这个结果可能不准</strong>（显示你的真实 IP）。不用慌，在浏览器里访问 <a href="https://httpbin.org/ip" target="_blank" rel="noreferrer">httpbin.org/ip</a> 验证，实际流量是走代理的。</p></blockquote><p>配置完，之后点击确定。</p><p><img src="https://pbs.twimg.com/media/HEydvGbaoAEMdrw?format=jpg&amp;name=large" alt="图像"></p><p><strong>5. 打开浏览器，测试效果</strong></p><p>新建浏览器之后，左边点击「环境管理」，右边就能看到刚才新建的浏览器 —— 「Claude AI 账号」</p><p><img src="https://pbs.twimg.com/media/HEydz5WbQAA4H3X?format=jpg&amp;name=large" alt="图像"></p><p>点击&quot;打开&quot;，启动这个 Profile 的浏览器。会打开两个页面，第一个页面如果显示的是国内 IP 不要慌没关系。</p><p><img src="https://pbs.twimg.com/media/HEyd3IOacAAQJqP?format=jpg&amp;name=large" alt="图像"></p><p>我们直接在浏览器里面访问 IP 检测网站即可，访问 <a href="https://httpbin.org/ip" target="_blank" rel="noreferrer">httpbin.org/ip</a>，确认出口 IP 是你的代理 IP，不是真实 IP。</p><p><img src="https://pbs.twimg.com/media/HEyd6kOasAEOWM-?format=jpg&amp;name=large" alt="图像"></p><p>然后访问 Claude 官网，一般主要住宅 IP 干净，你如果新注册的时候，应该会发现不再跳验证了。</p><p>这次登录成功之后，下次再打开这个 Profile，之前的登录态还在，不用重新登录。</p><p>这就是指纹浏览器的核心价值：<strong>给你的账号一个稳定、一致、干净的家。</strong></p><p><strong>Claude Code 登录</strong></p><blockquote><p>如果没有账号第一次使用，注册账号也是要自己在指纹浏览器注册。</p></blockquote><blockquote><p>如果真的跳了手机验证，我建议用接码平台，这里不详细说了，如果大家有兴趣就单独写一个简单的注册教程。</p></blockquote><p>现在你需要在 AdsPower 的浏览器里完成 Claude 的首次登录。</p><p>这里有个重要的细节：</p><p>当你在终端执行 claude login 的时候，Claude Code 会自动跳转到你的<strong>系统默认浏览器</strong>。但你不能让它跳到日常浏览器——那样就白配了。</p><p>正确做法：</p><ol><li>在终端执行 claude login</li><li><strong>不要点自动打开的浏览器页面</strong></li><li>复制终端里打印出来的登录 URL</li><li>打开 AdsPower，启动你的&quot;Claude 主号&quot;Profile</li><li>把 URL 粘贴到 AdsPower 的浏览器地址栏里</li><li>在这个指纹浏览器里完成登录</li></ol><p>看下面的图片步骤</p><p><img src="https://pbs.twimg.com/media/HEyeZMFbcAAH5R_?format=jpg&amp;name=large" alt="图像"></p><p>弹出来浏览器，直接关闭，回到终端复制链接</p><p><img src="https://pbs.twimg.com/media/HEyecJHbIAAx_h4?format=jpg&amp;name=large" alt="图像"></p><p>粘贴到指纹浏览器</p><p><img src="https://pbs.twimg.com/media/HEyef8DbQAAt9Ep?format=jpg&amp;name=large" alt="图像"></p><p>登录你的账号，我是 Google 账号注册的，直接登录了。</p><p><img src="https://pbs.twimg.com/media/HEyejUmboAAH2JN?format=jpg&amp;name=large" alt="图像"></p><p>登录成功，你的 Claude 账号<strong>从现在开始</strong>就在指纹浏览器的保护下了</p><p><img src="https://pbs.twimg.com/media/HEyellDbsAAcdiq?format=jpg&amp;name=large" alt="图像"></p><p>以后日常使用 Claude 网页端、登录、改设置，<strong>都走 AdsPower 的 Profile，不要用裸浏览器</strong>。<strong>不管多少个账号都这样操作</strong>。</p><h2 id="第四部分-正式订阅官方-claude" tabindex="-1">第四部分：正式订阅官方 Claude <a class="header-anchor" href="#第四部分-正式订阅官方-claude" aria-label="Permalink to &quot;第四部分：正式订阅官方 Claude&quot;">​</a></h2><p>网络环境搞定了，现在可以订阅了。</p><p>前面最麻烦的部分其实已经搞完了：</p><ul><li>第一部分，先把 Claude Code 跑起来，低成本先入门。</li><li>第二部分，再把 VPS + 住宅 IP 这条链路搭好，把环境稳定性补上。</li></ul><p>走到这里，整个闭环只差订阅了。</p><p><strong>用一种尽量简单、尽量稳妥的方式，完成官方订阅。</strong></p><p>这段时间 Claude 封号越来越多。有好的环境条件，再走正规订阅，整体会稳不少。</p><p>本部分主要就做四件事：</p><ol><li>准备一个美区 Apple ID</li><li>用 支付宝 购买官方 Apple 礼品卡</li><li>把礼品卡兑换到账号里</li><li>下载并登录 Claude AI 应用，完成套餐订阅</li></ol><p>整个流程不复杂，真正麻烦的通常只有第一次。</p><h2 id="第一步-准备一个美区-apple-id" tabindex="-1">第一步：准备一个美区 Apple ID <a class="header-anchor" href="#第一步-准备一个美区-apple-id" aria-label="Permalink to &quot;第一步：准备一个美区 Apple ID&quot;">​</a></h2><p>这个步骤我就不展开细写了，因为外面已经有很多成熟教程。</p><p>你可以直接参考这篇帖子，作者是 <a href="https://x.com/@lonely" target="_blank" rel="noreferrer">@lonely</a>：</p><p><a href="https://x.com/Lonely__MH/status/2031540200082649090?s=20" target="_blank" rel="noreferrer">https://x.com/Lonely__MH/status/2031540200082649090?s=20</a></p><h2 id="第二步-用支付宝购买官方-apple-礼品卡" tabindex="-1">第二步：用支付宝购买官方 Apple 礼品卡 <a class="header-anchor" href="#第二步-用支付宝购买官方-apple-礼品卡" aria-label="Permalink to &quot;第二步：用支付宝购买官方 Apple 礼品卡&quot;">​</a></h2><p>我的流程很简单：</p><ul><li>打开 支付宝</li><li>左上角切换地区</li><li>选择 国际/港澳台，搜索 旧金山</li><li>回到首页之后，选择 礼品卡</li><li>在礼品卡页面直接找 Apple 礼品卡</li><li>输入你需要的金额</li></ul><p>这里有个细节一定要注意：</p><p><strong>你 Apple ID 的账单地区，最好提前选成免税地区。</strong></p><p>因为你最终支付的是税后金额。如果账单地区本身带税，实际扣款会比你想的多一点。</p><p>如果你是第一次购买，通常还会遇到几步额外认证：</p><ul><li>上传身份证正反面</li><li>人脸识别</li><li>可能会弹出一个会员开通页面</li></ul><blockquote><p>我自己当时也碰到了那个弹窗，不点基本过不去，所以顺手点了。至少我当时没有被额外收费，但这一步你自己看清页面信息再操作。</p></blockquote><p>下面是对应界面的操作步骤：</p><p><img src="https://pbs.twimg.com/media/HEyewgWbQAAwMUS?format=jpg&amp;name=large" alt="图像"></p><p><img src="https://pbs.twimg.com/media/HEye90Wb0AA0wIe?format=jpg&amp;name=large" alt="图像"></p><h2 id="第三步-兑换礼品卡" tabindex="-1">第三步：兑换礼品卡 <a class="header-anchor" href="#第三步-兑换礼品卡" aria-label="Permalink to &quot;第三步：兑换礼品卡&quot;">​</a></h2><ul><li>复制购买成功后的礼品卡兑换码</li><li>打开 App Store</li><li>点击右上角头像</li><li>进入 兑换礼品卡</li><li>选择 手动输入礼品卡代码</li><li>把刚才复制的代码粘贴进去</li></ul><p>有时候系统还会附送一些额外权益。像我当时就弹了一个免费的 Apple TV 试用，但我没要。这个不是重点，看到也不用惊讶。</p><p>对应界面如下：</p><p><img src="https://pbs.twimg.com/media/HEyfBsmbQAAz8wA?format=jpg&amp;name=large" alt="图像"></p><h2 id="第四步-下载并登录-claude-ai-完成套餐订阅" tabindex="-1">第四步：下载并登录 Claude AI，完成套餐订阅 <a class="header-anchor" href="#第四步-下载并登录-claude-ai-完成套餐订阅" aria-label="Permalink to &quot;第四步：下载并登录 Claude AI，完成套餐订阅&quot;">​</a></h2><ul><li>在 App Store 搜索 Claude AI</li><li>下载应用</li><li>打开应用并登录你的账号</li><li>登录成功后，点击左上角</li><li>打开左侧边栏</li><li>点击左下角你的账户名</li><li>进入套餐订阅页面</li></ul><p>按照你自己的需求选套餐即可。</p><p>我当时看到的大概套餐信息是：</p><blockquote><p>Pro Plan：20 美元 Max Plan 5x：125 美元 Max Plan 20x：245 美元</p></blockquote><p>以上价格以 App 内实际显示为准，可能会有调整。</p><p>我这里因为已经订阅过了，所以没办法完整重演支付过程，但路径就是这条，不会太复杂。</p><p>相关界面如下：</p><p><img src="https://pbs.twimg.com/media/HEyfEG2a4AAskAA?format=jpg&amp;name=large" alt="图像"></p><p><img src="https://pbs.twimg.com/media/HEyfGPvacAAnoLf?format=jpg&amp;name=large" alt="图像"></p><h2 id="最后" tabindex="-1">最后 <a class="header-anchor" href="#最后" aria-label="Permalink to &quot;最后&quot;">​</a></h2><p>恭喜你。</p><p>你现在拥有的是：</p><ul><li>可用的 Claude Code</li><li>稳定的网络环境</li><li>安全的浏览器环境</li><li>相对安全、方便的订阅路径</li><li>官方原生模型的直接体验</li></ul><p>往期 Agent Team 实战教程系列</p><blockquote><p>3月23日</p></blockquote><blockquote><p>3月26日</p></blockquote>',144)]))}const u=p(o,[["render",r]]);export{c as __pageData,u as default};
